SELECT responsibility
FROM cultural_dimensions
WHERE country_id = 0;

SELECT country_name
FROM countries
WHERE region = 'Eastern Europe';

SELECT user_name, institution
FROM users
WHERE user_id > 5;

SELECT country_name, gdp_per_capita
FROM countries
WHERE gdp_per_capita > (SELECT AVG(gdp_per_capita) FROM countries);

SELECT * 
FROM data_sets 
WHERE TRIM(file_path) = 'data/2023_world_values_survey.csv';

SELECT DISTINCT c.country_id, c.country_name
FROM countries c
INNER JOIN cultural_dimensions cd ON c.country_id = cd.country_id;

SELECT country_name
FROM countries
WHERE gdp_per_capita = (SELECT MAX(gdp_per_capita) FROM countries);
